"import React from 'react';
import { motion } from 'framer-motion';

const pageVariants = {
  initial: {
    scale: 0.92,
    opacity: 0,
    filter: 'blur(12px)',
    y: -20
  },
  animate: {
    scale: 1,
    opacity: 1,
    filter: 'blur(0px)',
    y: 0,
    transition: {
      duration: 0.6,
      ease: [0.23, 1, 0.32, 1]
    }
  },
  exit: {
    scale: 0.92,
    opacity: 0,
    filter: 'blur(12px)',
    y: -20,
    transition: {
      duration: 0.6,
      ease: [0.23, 1, 0.32, 1]
    }
  }
};

export default function PageTransition({ children, className = '' }) {
  return (
    <motion.div
      initial="initial"
      animate="animate"
      exit="exit"
      variants={pageVariants}
      className={className}
      style={{ width: '100%', height: '100%' }}
    >
      {children}
    </motion.div>
  );
}"

