"import React, { useRef, useMemo } from 'react';
import { Canvas, useFrame } from '@react-three/fiber';
import { Stars, Text3D, Float, Center } from '@react-three/drei';
import * as THREE from 'three';

const OrbitingCoins = () => {
  const groupRef = useRef();

  const coins = useMemo(() => {
    return Array.from({ length: 8 }).map((_, i) => {
      const angle = (i / 8) * Math.PI * 2;
      const radius = 3 + Math.random() * 1.5;
      const speed = 0.5 + Math.random() * 0.5;
      return { angle, radius, speed, yOffset: (Math.random() - 0.5) * 2 };
    });
  }, []);

  useFrame(({ clock }) => {
    if (!groupRef.current) return;
    const time = clock.getElapsedTime();
    groupRef.current.children.forEach((child, i) => {
      const data = coins[i];
      const currentAngle = data.angle + time * data.speed;
      child.position.x = Math.cos(currentAngle) * data.radius;
      child.position.z = Math.sin(currentAngle) * data.radius;
      child.position.y = data.yOffset + Math.sin(time * 2 + i) * 0.5;
      child.rotation.y += 0.05;
      child.rotation.x += 0.02;
    });
  });

  return (
    <group ref={groupRef}>
      {coins.map((_, i) => (
        <mesh key={i} castShadow receiveShadow>
          <cylinderGeometry args={[0.4, 0.4, 0.05, 32]} />
          <meshStandardMaterial 
            color="#ffd700" 
            metalness={1} 
            roughness={0.2} 
            emissive="#332200" 
          />
        </mesh>
      ))}
    </group>
  );
};

