"import { useState, useEffect, useRef } from 'react';
import { gsap } from 'gsap';

export default function useCountUp(targetValue, duration = 2, delay = 0) {
  const [value, setValue] = useState(0);
  const objRef = useRef({ val: 0 });

  useEffect(() => {
    const obj = objRef.current;

    // Slot machine spin effect on change
    gsap.to(obj, {
      val: targetValue,
      duration: duration,
      delay: delay,
      ease: "elastic.out(1, 0.3)",
      onUpdate: () => {
        setValue(Math.ceil(obj.val));
      }
    });
  }, [targetValue, duration, delay]);

  return value;
}"

