import { motion } from 'framer-motion-3d';
import { formatCurrency } from '../../utils/formatters';

const TrendBar = ({ data, index, maxAmount, type }) => {
  const [hovered, setHovered] = useState(false);

  const isIncome = type === 'income';
  const amount = isIncome ? data.income : data.expense;
  const color = isIncome ? '#00ff88' : '#ff2244';

  // Calculate height proportional to maxAmount (max height = 5)
  const percentage = maxAmount > 0 ? amount / maxAmount : 0;
  const height = Math.max(0.2, percentage * 5);

  // Layout math
  const xOffset = index * 2.5 - 5; // Center the bars
  const barXOffset = isIncome ? -0.5 : 0.5; // Income left, Expense right
  const x = xOffset + barXOffset;

  return (
    <motion.group
      position={[x, 0, 0]}
      initial={{ scaleY: 0, y: -2 }}
      animate={{ scaleY: 1, y: 0 }}
      transition={{ 
        type: 'spring', 
        delay: index * 0.1 + (isIncome ? 0 : 0.05),
        stiffness: 120,
        damping: 10
      }}
    >
