import { MeshDistortMaterial, Float, Html } from '@react-three/drei';
import { motion } from 'framer-motion-3d';
import * as THREE from 'three';

const LiquidFill = ({ percentage }) => {
  const meshRef = useRef();

  // Determine liquid properties based on percentage
  let color = '#00ff88';
  let speed = 2;
  let distort = 0.2;

  if (percentage >= 100) {
    color = '#ff2244'; // Red lava
    speed = 10;
    distort = 0.8;
  } else if (percentage >= 80) {
    color = '#ff9900'; // Orange bubbling
    speed = 6;
    distort = 0.5;
  } else if (percentage >= 50) {
    color = '#ffd700'; // Yellow choppy
    speed = 4;
    distort = 0.4;
  }

  // Calculate height and position (Cylinder height is 2, so Y goes from -1 to 1)
  const clampedPct = Math.min(percentage, 100) / 100;
  const height = Math.max(0.1, clampedPct * 2);
  const yPos = -1 + (height / 2);

  return (
    <mesh position={[0, yPos, 0]} ref={meshRef}>
      <cylinderGeometry args={[0.95, 0.95, height, 32, 32]} />
      <MeshDistortMaterial
        color={color}
        emissive={color}
        emissiveIntensity={0.5}
        speed={speed}
        distort={distort}
        radius={1}
        transparent
        opacity={0.8}
      />
    </mesh>
  );
};

